def count_inversions_simple(arr):
    """Count inversions O(n²)"""
    count = 0
    n = len(arr)
    for i in range(n):
        for j in range(i+1, n):
            if arr[i] > arr[j]:
                count += 1
    return count

def count_inversions_merge(arr):
    """Count inversions O(n log n) using merge sort"""
    def merge_count(arr, temp, left, mid, right):
        i, j, k = left, mid + 1, left
        inv_count = 0

        while i <= mid and j <= right:
            if arr[i] <= arr[j]:
                temp[k] = arr[i]
                i += 1
            else:
                temp[k] = arr[j]
                inv_count += (mid - i + 1)  # All remaining in left are inversions
                j += 1
            k += 1

        while i <= mid:
            temp[k] = arr[i]
            i, k = i + 1, k + 1
        while j <= right:
            temp[k] = arr[j]
            j, k = j + 1, k + 1

        for i in range(left, right + 1):
            arr[i] = temp[i]

        return inv_count

    def sort_count(arr, temp, left, right):
        inv_count = 0
        if left < right:
            mid = (left + right) // 2
            inv_count += sort_count(arr, temp, left, mid)
            inv_count += sort_count(arr, temp, mid + 1, right)
            inv_count += merge_count(arr, temp, left, mid, right)
        return inv_count

    n = len(arr)
    temp = [0] * n
    arr_copy = arr.copy()
    return sort_count(arr_copy, temp, 0, n - 1)

# Examples
arr = [2, 4, 1, 3, 5]
print(f"Array: {arr}")
print(f"Inversions (simple): {count_inversions_simple(arr)}")
print(f"Inversions (merge): {count_inversions_merge(arr)}")

